def download_invoice(current_user_id: int, customer_id: int):
    """
    Facilitates downloading of an invoice based on authorization.
    :param current_user_id: int, the user requesting access to the invoice
    :param customer_id: int, the customer whose invoice is being accessed
    :return: The invoice details if authorized, else 'Unauthorized'
    """
    user_info = USER_ROLES.get(current_user_id)

    if not user_info:
        return "Unauthorized"

    role = user_info.get("role")

    # Authorization logic: Admin can access any invoice, 
    # customers can only access their own.
    if role == "admin" or current_user_id == customer_id:
        invoice = INVOICES.get(customer_id)
        if invoice:
            return invoice

    return "Unauthorized"

