    Permits only numbers and basic arithmetic operators (+, -, *, /).
    '''
    if not query or not isinstance(query, str):
        raise ValueError("Invalid input: Query must be a non-empty string.")

    # Define allowed operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def eval_node(node):
        if isinstance(node, ast.Constant):  # Python 3.8+
            if isinstance(node.value, (int, float)):
                return node.value
            raise TypeError(f"Unsupported constant type: {type(node.value)}")
        elif isinstance(node, ast.Num):  # Compatibility for older Python versions
            return node.n
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type in operators:
                left = eval_node(node.left)
                right = eval_node(node.right)
                return operators[op_type](left, right)
            raise TypeError(f"Unsupported binary operator: {op_type}")
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type in operators:
                operand = eval_node(node.operand)
                return operators[op_type](operand)
            raise TypeError(f"Unsupported unary operator: {op_type}")
        else:
            raise TypeError(f"Unsupported expression component: {type(node)}")

    try:
        # Parse the expression into an AST
        # mode='eval' ensures only a single expression is parsed
        tree = ast.parse(query, mode='eval')
        return eval_node(tree.body)
    except (SyntaxError, ZeroDivisionError, TypeError, ValueError) as e:
        # Return or raise the error depending on desired behavior
        # Here we raise it to indicate the computation failed
        raise e

