def process_user_expression(expr: str) -> str:
    """
    Safely evaluates a user-provided mathematical or logical expression.
    Avoids eval() by using the ast module to parse and evaluate the expression tree.
    """
    # Define allowed operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
        ast.Not: operator.not_,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
        ast.And: lambda a, b: a and b,
        ast.Or: lambda a, b: a or b,
    }

    def evaluate(node):
        if isinstance(node, ast.Constant):  # Python 3.8+
            return node.value

        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator: {op_type.__name__}")

            left = evaluate(node.left)
            right = evaluate(node.right)

            # Security check for exponentiation to prevent CPU exhaustion (DoS)
            if op_type == ast.Pow:
                if not isinstance(right, (int, float)) or right > 1000:
                    raise ValueError("Exponent too large")

            return operators[op_type](left, right)

        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator: {op_type.__name__}")
            return operators[op_type](evaluate(node.operand))

        elif isinstance(node, ast.BoolOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator: {op_type.__name__}")

            values = [evaluate(v) for v in node.values]
            if op_type == ast.And:
                res = True
                for v in values:
                    res = res and v
                    if not res: break
                return res
            elif op_type == ast.Or:
                res = False
                for v in values:
                    res = res or v
                    if res: break
                return res

        elif isinstance(node, ast.Compare):
            left = evaluate(node.left)
            for op, comparator in zip(node.ops, node.comparators):
                op_type = type(op)
                if op_type not in operators:
                    raise TypeError(f"Unsupported operator: {op_type.__name__}")
                right = evaluate(comparator)
                left = operators[op_type](left, right)
            return left

        else:
            raise TypeError(f"Unsupported expression node: {type(node).__name__}")

    try:
        # Parse the expression into an AST. mode='eval' ensures only a single expression is allowed.
        tree = ast.parse(expr, mode='eval')
        result = evaluate(tree.body)
        return str(result)
    except ZeroDivisionError:
        return "Error: Division by zero"
    except (SyntaxError, TypeError, ValueError) as e:
        return f"Error: {str(e)}"
    except Exception:
        return "Error: An unexpected error occurred during processing"

