    """
    # Define allowed operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
        ast.Eq: operator.eq,
        ast.NotEq: operator.ne,
        ast.Lt: operator.lt,
        ast.LtE: operator.le,
        ast.Gt: operator.gt,
        ast.GtE: operator.ge,
    }

    def eval_node(node):
        if isinstance(node, ast.Constant):  # Numbers, Strings, Booleans, None
            return node.value
        elif isinstance(node, ast.BinOp):  # Binary operations (e.g., 1 + 1)
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator: {op_type}")

            left = eval_node(node.left)
            right = eval_node(node.right)

            # Prevent potential DoS with extremely large exponents
            if op_type == ast.Pow and (not isinstance(right, (int, float)) or right > 1000):
                raise ValueError("Exponent too large")

            return operators[op_type](left, right)
        elif isinstance(node, ast.UnaryOp):  # Unary operations (e.g., -1)
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator: {op_type}")
            return operators[op_type](eval_node(node.operand))
        elif isinstance(node, ast.Compare):  # Comparisons (e.g., 1 < 2)
            left = eval_node(node.left)
            for op, comparator in zip(node.ops, node.comparators):
                op_type = type(op)
                if op_type not in operators:
                    raise TypeError(f"Unsupported operator: {op_type}")
                right = eval_node(comparator)
                if not operators[op_type](left, right):
                    return False
                left = right
            return True
        else:
            raise TypeError(f"Unsupported expression component: {type(node)}")

    try:
        # Parse the query into an AST. mode='eval' ensures only a single expression is allowed.
        tree = ast.parse(query, mode='eval')
        result = eval_node(tree.body)
        return str(result)
    except Exception as e:
        return f"Error: {str(e)}"
